            if FileManager.default.fileExists(atPath: path) {
                return true
            }
        }
        return false
    }
    
    private static func checkWritableSystemPaths() -> Bool {
        let paths = ["/", "/root/", "/private/", "/private/var/", "/System/"]
        for path in paths {
            let testFile = path + "jb_test_\(UUID().uuidString)"
            do {
                try "test".write(toFile: testFile, atomically: true, encoding: .utf8)
                try FileManager.default.removeItem(atPath: testFile)
                return true
            } catch {
                continue
            }
        }
        return false
    }
    
    private static func checkSuspiciousApps() -> Bool {
        let schemes = [
            "cydia://package/com.example.package",
            "sileo://package/com.example.package",
            "zbra://packages/com.example.package",
            "filza://",
            "undecimus://"
        ]
        
        for scheme in schemes {
            if let url = URL(string: scheme),
               UIApplication.shared.canOpenURL(url) {
