    }
    
    private static func checkDynamicLibraries() -> Bool {
        let suspiciousLibs = [
            "SubstrateLoader",
            "SSLKillSwitch",
            "SSLKillSwitch2",
            "MobileSubstrate",
            "TweakInject",
            "CydiaSubstrate",
            "cynject",
            "CustomWidgetIcons",
            "PreferenceLoader",
            "RocketBootstrap",
            "WeeLoader",
            "FridaGadget",
            "frida-agent",
            "libcycript"
        ]
        
        let count = _dyld_image_count()
        for i in 0..<count {
            guard let imageName = _dyld_get_image_name(i) else { continue }
            let name = String(cString: imageName)
            for lib in suspiciousLibs {
                if name.lowercased().contains(lib.lowercased()) {
                    return true
                }
            }
        }
        return false
    }
    
    private static func checkSandboxIntegrity() -> Bool {
        let pid = ProcessInfo.processInfo.processIdentifier
        var info = kinfo_proc()
        var size = MemoryLayout<kinfo_proc>.stride
        var mib: [Int32] = [CTL_KERN, KERN_PROC, KERN_PROC_PID, pid]
        let result = sysctl(&mib, UInt32(mib.count), &info, &size, nil, 0)
        if result != 0 {
            return false
        }
        // Check if being debugged (P_TRACED flag)
        if (info.kp_proc.p_flag & P_TRACED) != 0 {
            return true
        }
        return false
    }
    
    private static func checkSymbolicLinks() -> Bool {
        let suspiciousLinks = [
            "/var/lib/undecimus/apt",
            "/Applications",
            "/Library/Ringtones",
            "/Library/Wallpaper",
            "/usr/arm-apple-darwin9",
            "/usr/include",
            "/usr/libexec",
            "/usr/share"
        ]
        
        for link in suspiciousLinks {
            do {
                let attributes = try FileManager.default.attributesOfItem(atPath: link)
                if attributes[.type] as? FileAttributeType == .typeSymbolicLink {
                    return true
                }
            } catch {
                continue
            }
        }
        return false
    }
