class SecureKeyManager {
    
    static let shared = SecureKeyManager()
    
    private let keyTag = "com.cryptowallet.privatekey"
    private let encryptionKeyTag = "com.cryptowallet.encryptionkey"
    private let walletDataService = "com.cryptowallet.walletdata"
    
    private init() {}
    
    // MARK: - Device Integrity Gate
    
    private func ensureDeviceIntegrity() throws {
        if DeviceIntegrityChecker.isDeviceCompromised() {
            throw KeychainError.deviceCompromised
        }
    }
    
    // MARK: - Biometric Authentication
    
    private func authenticateUser(reason: String, completion: @escaping (Result<Void, Error>) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Cancel"
        
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            // Fall back to passcode
            context.evaluatePolicy(.deviceOwnerAuthentication, localizedReason: reason) { success, authError in
                if success {
                    completion(.success(()))
                } else {
                    completion(.failure(authError ?? KeychainError.biometricAuthFailed))
                }
            }
            return
        }
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, authError in
            if success {
                completion(.success(()))
            } else {
                completion(.failure(authError ?? KeychainError.biometricAuthFailed))
            }
        }
