    private func generateAndStoreKeys() throws -> WalletKeys {
        // Generate a 256-bit private key for secp256k1 (used in Bitcoin/Ethereum)
        var privateKeyBytes = [UInt8](repeating: 0, count: 32)
        let status = SecRandomCopyBytes(kSecRandomDefault, 32, &privateKeyBytes)
        guard status == errSecOK else {
            throw KeychainError.keyGenerationFailed("Random generation failed")
        }
        
        let privateKeyData = Data(privateKeyBytes)
        
