    // MARK: - Secure Enclave Encryption Key
    
    private func getOrCreateEncryptionKey() throws -> SecKey {
        // Try to retrieve existing key
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: encryptionKeyTag.data(using: .utf8)!,
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecReturnRef as String: true
        ]
        
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        
        if status == errSecSuccess, let key = item {
            return key as! SecKey
        }
        
        // Create new Secure Enclave key
        let access = SecAccessControlCreateWithFlags(
            kCFAllocatorDefault,
            kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            [.privateKeyUsage, .biometryCurrentSet],
            nil
        )!
        
        let attributes: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits as String: 256,
            kSecAttrTokenID as String: kSecAttrTokenIDSecureEnclave,
            kSecPrivateKeyAttrs as String: [
                kSecAttrIsPermanent as String: true,
                kSecAttrApplicationTag as String: encryptionKeyTag.data(using: .utf8)!,
                kSecAttrAccessControl as String: access
            ]
        ]
        
        var error: Unmanaged<CFError>?
        guard let privateKey = SecKeyCreateRandomKey(attributes as CFDictionary, &error) else {
            // Fallback for devices without Secure Enclave (simulator)
            return try createSoftwareEncryptionKey()
        }
        
        return privateKey
    }
    
    private func createSoftwareEncryptionKey() throws -> SecKey {
        let access = SecAccessControlCreateWithFlags(
            kCFAllocatorDefault,
            kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            [.privateKeyUsage],
            nil
        )!
        
        let attributes: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits as String: 256,
            kSecPrivateKeyAttrs as String: [
                kSecAttrIsPermanent as String: true,
                kSecAttrApplicationTag as String: encryptionKeyTag.data(using: .utf8)!,
                kSecAttrAccessControl as String: access
            ]
        ]
        
        var error: Unmanaged<CFError>?
        guard let privateKey = SecKeyCreateRandomKey(attributes as CFDictionary, &error) else {
            throw KeychainError.keyGenerationFailed(error?.takeRetainedValue().localizedDescription ?? "Unknown")
        }
        
        return privateKey
    }
    
    private func encryptPrivateKey(_ data: Data) throws -> Data {
        let encKey = try getOrCreateEncryptionKey()
        guard let publicKey = SecKeyCopyPublicKey(encKey) else {
            throw KeychainError.encryptionFailed
        }
        
        var error: Unmanaged<CFError>?
        guard let encryptedData = SecKeyCreateEncryptedData(
            publicKey,
            .eciesEncryptionCofactorVariableIVX963SHA256AESGCM,
            data as CFData,
            &error
        ) else {
            throw KeychainError.encryptionFailed
        }
        
        return encryptedData as Data
    }
    
    private func decryptPrivateKey(_ encryptedData: Data) throws -> Data {
        let encKey = try getOrCreateEncryptionKey()
        
        var error: Unmanaged<CFError>?
        guard let decryptedData = SecKeyCreateDecryptedData(
            encKey,
            .eciesEncryptionCofactorVariableIVX963SHA256AESGCM,
            encryptedData as CFData,
            &error
        ) else {
            throw KeychainError.decryptionFailed
        }
        
        return decryptedData as Data
    }
    
    // MARK: - Keychain Storage
    
    private func storeInKeychain(data: Data, forKey key: String) throws {
        let access = SecAccessControlCreateWithFlags(
            kCFAllocatorDefault,
            kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            [.biometryCurrentSet, .or, .devicePasscode],
            nil
        )!
        
        // Delete existing item first
        let deleteQuery: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: walletDataService,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(deleteQuery as CFDictionary)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: walletDataService,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessControl as String: access,
            kSecAttrSynchronizable as String: false // Never sync to iCloud
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw KeychainError.keychainError(status)
        }
    }
    
    private func retrieveFromKeychain(forKey key: String) throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: walletDataService,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        
        guard status == errSecSuccess, let data = item as? Data else {
            throw KeychainError.keyNotFound
        }
        
        return data
    }
    
    func deleteKey(forAddress address: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: walletDataService,
            kSecAttrAccount as String: keyTag + "." + address
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw KeychainError.keychainError(status)
        }
    }
    
    // MARK: - Key Derivation Helpers
    
    private func derivePublicKey(from privateKeyData: Data) -> Data {
        // In production, use libsecp256k1 for proper secp256k1 public key derivation
        // This is a simplified version using P256 for demonstration
        let privateKey = P256.Signing.PrivateKey(rawRepresentation: privateKeyData.prefix(32))
        return privateKey.publicKey.rawRepresentation
    }
    
    private func deriveAddress(from publicKey: Data) -> String {
        // Keccak-256 hash of public key, take last 20 bytes (Ethereum-style)
        let hash = sha256(data: publicKey)
        let addressBytes = hash.suffix(20)
        return "0x" + addressBytes.hexEncodedString()
    }
    
    private func sha256(data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_SHA256($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
    
    // MARK: - Transaction Signing
    
    func signTransaction(_ transaction: Transaction, forAddress address: String, completion: @escaping (Result<SignedTransaction, Error>) -> Void) {
        do {
            try ensureDeviceIntegrity()
        } catch {
            completion(.failure(error))
            return
        }
        
        authenticateUser(reason: "Authenticate to sign transaction") { [weak self] result in
            switch result {
            case .success:
                do {
                    guard let self = self else { return }
                    let signed = try self.performSigning(transaction, forAddress: address)
                    completion(.success(signed))
                } catch {
                    completion(.failure(error))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    private func performSigning(_ transaction: Transaction, forAddress address: String) throws -> SignedTransaction {
        // Retrieve and decrypt private key
        let encryptedKey = try retrieveFromKeychain(forKey: keyTag + "." + address)
        let privateKeyData = try decryptPrivateKey(encryptedKey)
        
        // Serialize transaction
        let txData = try transaction.serialize()
        
        // Hash the transaction
        let txHash = sha256(data: txData)
        
        // Sign with P256 (in production, use secp256k1)
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData.prefix(32))
        let signature = try privateKey.signature(for: txHash)
        
        // Clear private key from memory
        var mutableKeyData = [UInt8](privateKeyData)
        mutableKeyData.withUnsafeMutableBufferPointer { buffer in
            memset_s(buffer.baseAddress!, buffer.count, 0, buffer.count)
        }
        
        return SignedTransaction(
            transaction: transaction,
            signature: signature.rawRepresentation.hexEncodedString(),
            txHash: txHash.hexEncodedString()
        )
    }
    
    // MARK: - List Wallets
    
    func listWalletAddresses() throws -> [String] {
        try ensureDeviceIntegrity()
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: walletDataService,
            kSecReturnAttributes as String: true,
            kSecMatchLimit as String: kSecMatchLimitAll
        ]
        
        var items: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &items)
        
        guard status == errSecSuccess, let results = items as? [[String: Any]] else {
            if status == errSecItemNotFound { return [] }
            throw KeychainError.keychainError(status)
        }
        
        return results.compactMap { dict in
            guard let account = dict[kSecAttrAccount as String] as? String,
                  account.hasPrefix(keyTag + ".") else { return nil }
            return String(account.dropFirst(keyTag.count + 1))
        }
    }
