// MARK: - Blockchain Communication

enum NetworkError: Error, LocalizedError {
    case invalidURL
    case requestFailed(String)
    case invalidResponse
    case rpcError(Int, String)
    case deviceCompromised
    
    var errorDescription: String? {
        switch self {
        case .invalidURL: return "Invalid URL"
        case .requestFailed(let msg): return "Request failed: \(msg)"
        case .invalidResponse: return "Invalid response"
        case .rpcError(let code, let msg): return "RPC Error \(code): \(msg)"
        case .deviceCompromised: return "Device integrity check failed"
        }
    }
}

struct RPCRequest: Codable {
    let jsonrpc: String
    let method: String
    let params: [RPCParam]
    let id: Int
}

enum RPCParam: Codable {
    case string(String)
    case int(Int)
    case dict([String: String])
    case array([String])
    
    func encode(to encoder: Encoder) throws {
        var container = encoder.singleValueContainer()
        switch self {
        case .string(let value): try container.encode(value)
        case .int(let value): try container.encode(value)
        case .dict(let value): try container.encode(value)
        case .array(let value): try container.encode(value)
        }
    }
    
    init(from decoder: Decoder) throws {
        let container = try decoder.singleValueContainer()
        if let value = try? container.decode(String.self) {
            self = .string(value)
        } else if let value = try? container.decode(Int.self) {
            self = .int(value)
        } else if let value = try? container.decode([String: String].self) {
            self = .dict(value)
        } else if let value = try? container.decode([String].self) {
            self = .array(value)
        } else {
            throw DecodingError.typeMismatch(RPCParam.self, .init(codingPath: decoder.codingPath, debugDescription: "Unknown type"))
        }
    }
}

struct RPCResponse: Codable {
    let jsonrpc: String
    let id: Int
    let result: String?
    let error: RPCError?
}

struct RPCError: Codable {
    let code: Int
    let message: String
}

class BlockchainService {
    
    static let shared = BlockchainService()
    
    private let session: URLSession
    private var rpcURL: URL
    
    private init() {
        let config = URLSessionConfiguration.ephemeral
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.urlCache = nil
        config.httpCookieStorage = nil
        config.requestCachePolicy = .reloadIgnoringLocalAndRemoteCacheData
        
        // Certificate pinning delegate
        self.session = URLSession(configuration: config, delegate: SSLPinningDelegate(), delegateQueue: nil)
        self.rpcURL = URL(string: "https://mainnet.infura.io/v3/YOUR_PROJECT_ID")!
    }
    
    func configure(rpcEndpoint: String) throws {
        guard let url = URL(string: rpcEndpoint) else {
            throw NetworkError.invalidURL
        }
        self.rpcURL = url
    }
    
    // MARK: - Get Balance
    
    func getBalance(address: String, completion: @escaping (Result<String, Error>) -> Void) {
        guard !DeviceIntegrityChecker.isDeviceCompromised() else {
            completion(.failure(NetworkError.deviceCompromised))
            return
        }
        
        let request = RPCRequest(
            jsonrpc: "2.0",
            method: "eth_getBalance",
            params: [.string(address), .string("latest")],
            id: 1
        )
        
        sendRPCRequest(request, completion: completion)
    }
    
    // MARK: - Get Transaction Count (Nonce)
    
    func getTransactionCount(address: String, completion: @escaping (Result<String, Error>) -> Void) {
        guard !DeviceIntegrityChecker.isDeviceCompromised() else {
