    // MARK: - Estimate Gas
    
    func estimateGas(from: String, to: String, value: String, data: String = "0x", completion: @escaping (Result<String, Error>) -> Void) {
        guard !DeviceIntegrityChecker.isDeviceCompromised() else {
            completion(.failure(NetworkError.deviceCompromised))
