            params: [.string(txHash)],
            id: 1
        )
        
        sendRPCRequest(request, completion: completion)
    }
    
    // MARK: - RPC Request Helper
    
    private func sendRPCRequest(_ rpcRequest: RPCRequest, completion: @escaping (Result<String, Error>) -> Void) {
        var urlRequest = URLRequest(url: rpcURL)
        urlRequest.httpMethod = "POST"
        urlRequest.setValue("application/json", forHTTPHeaderField: "Content-Type")
        urlRequest.timeoutInterval = 30
        
        do {
            urlRequest.httpBody = try JSONEncoder().encode(rpcRequest)
        } catch {
            completion(.failure(error))
            return
        }
        
        let task = session.dataTask(with: urlRequest) { data, response, error in
            if let error = error {
                completion(.failure(NetworkError.requestFailed(error.localizedDescription)))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse,
                  (200...299).contains(httpResponse.statusCode) else {
                completion(.failure(NetworkError.invalidResponse))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.invalidResponse))
                return
            }
            
            do {
                let rpcResponse = try JSONDecoder().decode(RPCResponse.self, from: data)
                
                if let error = rpcResponse.error {
                    completion(.failure(NetworkError.rpcError(error.code, error.message)))
                    return
                }
                
                guard let result = rpcResponse.result else {
                    completion(.failure(NetworkError.invalidResponse))
                    return
                }
                
                completion(.success(result))
            } catch {
                completion(.failure(error))
            }
        }
        
        task.resume()
    }
}

// MARK: - SSL Pinning Delegate

class SSLPinningDelegate: NSObject, URLSessionDelegate {
    
    // In production, embed your server's certificate public key hash
    private let pinnedPublicKeyHashes: [String] = [
        // Add SHA-256 hashes of your server's public keys
        // "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA="
    ]
    
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // If no pinned keys configured, use default validation (development mode)
        if pinnedPublicKeyHashes.isEmpty {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        // Validate server trust
        var error: CFError?
        let isValid = SecTrustEvaluateWithError(serverTrust, &error)
        
        guard isValid else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Check public key pinning
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        var foundMatch = false
        
        for i in 0..<certificateCount {
            guard let certificate = SecTrustGetCertificateAtIndex(serverTrust, i),
                  let publicKey = SecCertificateCopyKey(certificate),
                  let publicKeyData = SecKeyCopyExternalRepresentation(publicKey, nil) as Data? else {
                continue
            }
            
            let hash = SHA256.hash(data: publicKeyData)
            let hashString = Data(hash).base64EncodedString()
            
            if pinnedPublicKeyHashes.contains(hashString) {
                foundMatch = true
                break
            }
        }
        
        if foundMatch {
            completionHandler(.useCredential, URLCredential(trust: serverTrust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}

// MARK: - Wallet Manager (High-level API)

class WalletManager {
    
    static let shared = WalletManager()
    
    private let keyManager = SecureKeyManager.shared
    private let blockchain = BlockchainService.shared
    
    private init() {}
    
    // MARK: - Create Wallet
    
    func createWallet(completion: @escaping (Result<WalletKeys, Error>) -> Void) {
        keyManager.generateWalletKeys(completion: completion)
    }
    
    // MARK: - Get Balance
    
    func getBalance(address: String, completion: @escaping (Result<String, Error>) -> Void) {
        blockchain.getBalance(address: address) { result in
            switch result {
            case .success(let hexBalance):
                // Convert hex to decimal ETH
                let weiString = String(hexBalance.dropFirst(2)) // Remove 0x
                if let wei = UInt64(weiString, radix: 16) {
                    let eth = Double(wei) / 1e18
                    completion(.success(String(format: "%.6f ETH", eth)))
                } else {
                    completion(.success(hexBalance))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    // MARK: - Send Transaction
    
    func sendTransaction(from: String, to: String, valueInWei: String, completion: @escaping (Result<String, Error>) -> Void) {
        
        // Step 1: Get nonce
        blockchain.getTransactionCount(address: from) { [weak self] nonceResult in
            guard let self = self else { return }
            
            switch nonceResult {
            case .success(let nonceHex):
                let nonce = UInt64(nonceHex.dropFirst(2), radix: 16) ?? 0
                
                // Step 2: Get gas price
                self.blockchain.getGasPrice { gasPriceResult in
                    switch gasPriceResult {
                    case .success(let gasPriceHex):
                        // Step 3: Create and sign transaction
                        let transaction = Transaction(
                            nonce: nonce,
                            to: to,
                            value: valueInWei,
                            gasPrice: gasPriceHex,
                            gasLimit: 21000,
                            data: "0x",
                            chainId: 1
                        )
                        
                        self.keyManager.signTransaction(transaction, forAddress: from) { signResult in
                            switch signResult {
                            case .success(let signedTx):
                                // Step 4: Broadcast
                                self.blockchain.sendRawTransaction(signedTxHex: "0x" + signedTx.signature) { broadcastResult in
                                    completion(broadcastResult)
                                }
                            case .failure(let error):
                                completion(.failure(error))
                            }
                        }
                        
                    case .failure(let error):
                        completion(.failure(error))
                    }
                }
                
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    // MARK: - List Wallets
    
    func listWallets() -> [String] {
        return (try? keyManager.listWalletAddresses()) ?? []
    }
    
    // MARK: - Delete Wallet
    
    func deleteWallet(address: String) throws {
        try keyManager.deleteKey(forAddress: address)
    }
}

// MARK: - Data Extension

extension Data {
    func hexEncodedString() -> String {
        return map { String(format: "%02hhx", $0) }.joined()
    }
    
    init?(hexString: String) {
        let hex = hexString.hasPrefix("0x") ? String(hexString.dropFirst(2)) : hexString
        let len = hex.count / 2
        var data = Data(capacity: len)
        var index = hex.startIndex
        for _ in 0..<len {
            let nextIndex = hex.index(index, offsetBy: 2)
            guard let byte = UInt8(hex[index..<nextIndex], radix: 16) else { return nil }
            data.append(byte)
            index = nextIndex
        }
        self = data
    }
}

