// MARK: - UI Layer

class WalletViewController: UIViewController {
    
    private let walletManager = WalletManager.shared
    
    private let statusLabel: UILabel = {
        let label = UILabel()
        label.numberOfLines = 0
        label.textAlignment = .center
        label.font = .systemFont(ofSize: 14)
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let addressLabel: UILabel = {
        let label = UILabel()
        label.numberOfLines = 0
        label.textAlignment = .center
        label.font = .monospacedSystemFont(ofSize: 12, weight: .regular)
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let balanceLabel: UILabel = {
        let label = UILabel()
        label.textAlignment = .center
        label.font = .systemFont(ofSize: 24, weight: .bold)
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let createWalletButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Create New Wallet", for: .normal)
        button.titleLabel?.font = .systemFont(ofSize: 18, weight: .semibold)
        button.backgroundColor = .systemBlue
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 12
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    private let refreshButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Refresh Balance", for: .normal)
        button.titleLabel?.font = .systemFont(ofSize: 16)
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    private let sendButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Send Transaction", for: .normal)
        button.titleLabel?.font = .systemFont(ofSize: 18, weight: .semibold)
        button.backgroundColor = .systemGreen
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 12
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    private let securityStatusView: UIView = {
        let view = UIView()
        view.layer.cornerRadius = 8
        view.translatesAutoresizingMaskIntoConstraints = false
        return view
    }()
    
    private let securityLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 12, weight: .medium)
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private var currentAddress: String?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        checkDeviceSecurity()
        loadExistingWallet()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Crypto Wallet"
        
        view.addSubview(securityStatusView)
        securityStatusView.addSubview(securityLabel)
        view.addSubview(addressLabel)
        view.addSubview(balanceLabel)
        view.addSubview(statusLabel)
        view.addSubview(createWalletButton)
        view.addSubview(refreshButton)
        view.addSubview(sendButton)
        
        NSLayoutConstraint.activate([
            securityStatusView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 8),
            securityStatusView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            securityStatusView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
            securityStatusView.heightAnchor.constraint(equalToConstant: 32),
            
            securityLabel.centerXAnchor.constraint(equalTo: securityStatusView.centerXAnchor),
            securityLabel.centerYAnchor.constraint(equalTo: securityStatusView.centerYAnchor),
            
            addressLabel.topAnchor.constraint(equalTo: securityStatusView.bottomAnchor, constant: 20),
            addressLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            addressLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
            
            balanceLabel.topAnchor.constraint(equalTo: addressLabel.bottomAnchor, constant: 16),
            balanceLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            balanceLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
            
            statusLabel.topAnchor.constraint(equalTo: balanceLabel.bottomAnchor, constant: 16),
            statusLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            statusLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
            
            createWalletButton.topAnchor.constraint(equalTo: statusLabel.bottomAnchor, constant: 32),
            createWalletButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            createWalletButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            createWalletButton.heightAnchor.constraint(equalToConstant: 50),
            
            refreshButton.topAnchor.constraint(equalTo: createWalletButton.bottomAnchor, constant: 16),
            refreshButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            sendButton.topAnchor.constraint(equalTo: refreshButton.bottomAnchor, constant: 16),
            sendButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            sendButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            sendButton.heightAnchor.constraint(equalToConstant: 50),
        ])
        
        createWalletButton.addTarget(self, action: #selector(createWalletTapped), for: .touchUpInside)
        refreshButton.addTarget(self, action: #selector(refreshBalanceTapped), for: .touchUpInside)
        sendButton.addTarget(self, action: #selector(sendTransactionTapped), for: .touchUpInside)
    }
    
    private func checkDeviceSecurity() {
        if DeviceIntegrityChecker.isDeviceCompromised() {
            securityStatusView.backgroundColor = .systemRed.withAlphaComponent(0.2)
            securityLabel.text = "⚠️ Device Compromised - Wallet Disabled"
            securityLabel.textColor = .systemRed
            createWalletButton.isEnabled = false
            sendButton.isEnabled = false
            
            let alert = UIAlertController(
                title: "Security Warning",
                message: "This device appears to be jailbroken or compromised. Wallet functionality has been disabled to protect your funds.",
                preferredStyle: .alert
            )
            alert.addAction(UIAlertAction(title: "OK", style: .default))
            present(alert, animated: true)
        } else {
            securityStatusView.backgroundColor = .systemGreen.withAlphaComponent(0.2)
            securityLabel.text = "✅ Device Secure"
            securityLabel.textColor = .systemGreen
        }
    }
    
    private func loadExistingWallet() {
        let wallets = walletManager.listWallets()
        if let firstWallet = wallets.first {
            currentAddress = firstWallet
            addressLabel.text = "Address: \(firstWallet)"
            refreshBalance()
        } else {
            addressLabel.text = "No wallet found"
            balanceLabel.text = ""
        }
    }
    
    @objc private func createWalletTapped() {
        statusLabel.text = "Creating wallet..."
        createWalletButton.isEnabled = false
        
        walletManager.createWallet { [weak self] result in
            DispatchQueue.main.async {
                self?.createWalletButton.isEnabled = true
                switch result {
                case .success(let keys):
                    self?.currentAddress = keys.address
                    self?.addressLabel.text = "Address: \(keys.address)"
                    self?.statusLabel.text = "Wallet created successfully!"
                    self?.refreshBalance()
                case .failure(let error):
                    self?.statusLabel.text = "Error: \(error.localizedDescription)"
                }
            }
        }
    }
    
    @objc private func refreshBalanceTapped() {
        refreshBalance()
    }
    
    private func refreshBalance() {
        guard let address = currentAddress else { return }
        
        balanceLabel.text = "Loading..."
        
        walletManager.getBalance(address: address) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let balance):
                    self?.balanceLabel.text = balance
                case .failure(let error):
                    self?.balanceLabel.text = "Error"
                    self?.statusLabel.text = error.localizedDescription
                }
            }
        }
    }
    
    @objc private func sendTransactionTapped() {
        guard let fromAddress = currentAddress else {
            statusLabel.text = "Create a wallet first"
            return
        }
        
        let alert = UIAlertController(title: "Send Transaction", message: "Enter recipient details", preferredStyle: .alert)
        
        alert.addTextField { textField in
            textField.placeholder = "Recipient Address (0x...)"
            textField.autocapitalizationType = .none
        }
        
        alert.addTextField { textField in
            textField.placeholder = "Amount in Wei"
            textField.keyboardType = .numberPad
        }
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Send", style: .default) { [weak self] _ in
            guard let toAddress = alert.textFields?[0].text, !toAddress.isEmpty,
                  let amount = alert.textFields?[1].text, !amount.isEmpty else {
                self?.statusLabel.text = "Invalid input"
                return
            }
            
            // Input validation
            guard toAddress.hasPrefix("0x"), toAddress.count == 42 else {
                self?.statusLabel.text = "Invalid address format"
                return
            }
            
            self?.statusLabel.text = "Signing and sending..."
            self?.sendButton.isEnabled = false
            
            self?.walletManager.sendTransaction(from: fromAddress, to: toAddress, valueInWei: amount) { result in
                DispatchQueue.main.async {
                    self?.sendButton.isEnabled = true
                    switch result {
                    case .success(let txHash):
                        self?.statusLabel.text = "TX Sent: \(txHash)"
                        self?.refreshBalance()
                    case .failure(let error):
                        self?.statusLabel.text = "Error: \(error.localizedDescription)"
                    }
                }
            }
        })
        
        present(alert, animated: true)
    }
}

// MARK: - App Delegate

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        
        window = UIWindow(frame: UIScreen.main.bounds)
        let navController = UINavigationController(rootViewController: WalletViewController())
        window?.rootViewController = navController
        window?.makeKeyAndVisible()
        
        return true
    }
    
    func applicationDidEnterBackground(_ application: UIApplication) {
        // Add blur overlay to prevent screenshot of sensitive data
        let blurEffect = UIBlurEffect(style: .light)
        let blurView = UIVisualEffectView(effect: blurEffect)
        blurView.frame = window?.bounds ?? .zero
        blurView.tag = 999
        window?.addSubview(blurView)
    }
    
    func applicationWillEnterForeground(_ application: UIApplication) {
        // Remove blur overlay
        window?.viewWithTag(999)?.removeFromSuperview()
    }
}